{
    if (x < 0 || x >= width || y < 0 || y >= height) {
        std::cerr << "World.cpp - checkItem: Invalid position (" << x << ", " << y << ") for checking Item" << std::endl;
        return false;
    }

    for (auto& actor : worldMap[y][x]) {
        if (dynamic_cast<Item*>(actor)) {
            return true;
        }
